  ('pukao-7fec267e-moex-00342', 'pukao-7fec267e', 'pukao-7fec267e-moex-112-4dccc0e6', 'sub-pukao-7fec267e-02', NULL, 'single_choice', '以領導者對於領導方式的區分，可以分為民主式領導、獨裁式領導以及放任式領導。關於其領導特色，下 列敘述何者錯誤？', '["在民主式領導中，領導者賦予部屬較大的自由空間", "獨裁式領導方式下常會出現怠工現象", "放任式領導很少主動給予部屬指導，除非部屬前來請示，否則不表示任何意見", "獨裁式領導是效果最差的一種領導方式"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:15+00:00", "source_pdf_sha1": "64bf518f70b8", "answer_pdf_sha1": "7ce0a260f6de", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "401", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00343', 'pukao-7fec267e', 'pukao-7fec267e-moex-112-4dccc0e6', 'sub-pukao-7fec267e-02', NULL, 'single_choice', '「讓風險利益相關者瞭解所面對的風險，並參與決策，進而瞭解風險管理的作用，在風險管理的過程中取 得信任」。這段敘述在說明下列何種概念？', '["風險評估", "風險轉移", "風險規避", "風險溝通"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:15+00:00", "source_pdf_sha1": "64bf518f70b8", "answer_pdf_sha1": "7ce0a260f6de", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "401", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00344', 'pukao-7fec267e', 'pukao-7fec267e-moex-112-4dccc0e6', 'sub-pukao-7fec267e-02', NULL, 'single_choice', '關於知識管理之敘述，下列何者錯誤？', '["係針對既有經驗的整理，與創新無關", "是指能系統化建立、革新及應用組織中的核心知識", "使組織之核心知識發揮極大化效率，為組織帶來利益", "係指善用組織中的知識，以改善組織績效為導向"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:15+00:00", "source_pdf_sha1": "64bf518f70b8", "answer_pdf_sha1": "7ce0a260f6de", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "401", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00345', 'pukao-7fec267e', 'pukao-7fec267e-moex-112-4dccc0e6', 'sub-pukao-7fec267e-02', NULL, 'single_choice', '關於電子化政府的各項服務，下列何者屬於G2G的範疇？', '["線上申報個人綜合所得稅", "健保APP開放下載", "公司設立登記之線上申辦", "跨機關電子公文交換"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:15+00:00", "source_pdf_sha1": "64bf518f70b8", "answer_pdf_sha1": "7ce0a260f6de", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "401", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00346', 'pukao-7fec267e', 'pukao-7fec267e-moex-112-4dccc0e6', 'sub-pukao-7fec267e-02', NULL, 'single_choice', '下列何者最能解釋「榖賤傷農，榖貴傷民」此公共問題發生的主要原因？', '["第三部門失靈", "市場失靈", "政策失靈", "自然獨占"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:15+00:00", "source_pdf_sha1": "64bf518f70b8", "answer_pdf_sha1": "7ce0a260f6de", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "401", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 38, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
